class cmsmastersDemosPreview{elements={};constructor(){this.initElements();this.bindEvents()}
initElements(){this.elements.$html=jQuery('html');this.elements.$container=jQuery('.cmsmasters-demos-preview');this.elements.$previewToggle=jQuery('.cmsmasters-preview__toggle');this.elements.$previewClose=jQuery('.cmsmasters-preview__close');const demoSkins=this.elements.$container.attr('data-demo-skins');if('true'===demoSkins||!0===demoSkins||'1'===demoSkins){this.elements.$previewDemo=jQuery('.cmsmasters-palettes-preview__demo');this.elements.$previewPalettes=jQuery('.cmsmasters-color-palettes');this.elements.$previewApply=jQuery('.cmsmasters-palettes-preview__apply');this.elements.$palettesDemoHeading=jQuery('.cmsmasters-palettes-preview__demo-heading');this.elements.$palettesPreviewToggle=jQuery('.cmsmasters-palettes-preview__toggle')}}
bindEvents(){const siteName=this.elements.$container.attr('data-site-name');const demoSkins=this.elements.$container.attr('data-demo-skins');if('true'===demoSkins||!0===demoSkins||'1'===demoSkins){this.elements.$html.attr('data-cmsmasters-color-palette',siteName);jQuery('.cmsmasters-palette-apply-active .cmsmasters-palettes-preview__apply').addClass('cmsmasters-palettes-preview__reset');jQuery('.cmsmasters-palette-apply-active .cmsmasters-palettes-preview__reset').text('Reset')}
this.elements.$previewToggle.on('click',this.togglePreview.bind(this));this.elements.$previewClose.on('click',this.closePreview.bind(this));if('true'===demoSkins||!0===demoSkins||'1'===demoSkins){this.elements.$palettesDemoHeading.on('click',this.clickPalettesDemoHeading.bind(this));this.elements.$previewApply.on('click',this.clickPreviewApply.bind(this));this.elements.$palettesPreviewToggle.one('click',function(){jQuery('.cmsmasters-color-palettes input.cmsmasters-palette-color').each(function(index,event){this.initPalettesColors(index,event)}.bind(this))}.bind(this))}}
togglePreview(event){const $this=jQuery(event.currentTarget);if('active'===$this.attr('data-condition')){$this.attr('data-condition','disable');this.elements.$html.attr('data-cmsmasters-condition','disable');return}
this.elements.$previewToggle.attr('data-condition','disable');$this.attr('data-condition','active');this.elements.$html.attr('data-cmsmasters-condition',`active-${$this.attr( 'data-name' )}`)}
closePreview(){this.elements.$html.attr('data-cmsmasters-condition','disable');this.elements.$previewToggle.attr('data-condition','disable')}
clickPalettesDemoHeading(event){const $this=jQuery(event.currentTarget).closest('.cmsmasters-palettes-preview__demo');if(!$this.hasClass('cmsmasters-palette-apply-no-active')){return}
this.elements.$previewDemo.addClass('cmsmasters-palette-apply-no-active').removeClass('cmsmasters-palette-apply-active');$this.removeClass('cmsmasters-palette-apply-no-active').addClass('cmsmasters-palette-apply-active');jQuery('.cmsmasters-palettes-preview__demo .cmsmasters-palettes-preview__apply').removeClass('cmsmasters-palettes-preview__reset').text('Apply');jQuery('.cmsmasters-palette-apply-active .cmsmasters-palettes-preview__apply').addClass('cmsmasters-palettes-preview__reset');jQuery('.cmsmasters-palette-apply-active .cmsmasters-palettes-preview__reset').text('Reset');const paletteIndex=$this.attr('data-palette-index');this.elements.$html.attr('data-cmsmasters-color-palette',paletteIndex);jQuery('.cmsmasters-palette-apply-no-active .cmsmasters-color-palettes .wp-picker-default').trigger('click');this.elements.$html.removeAttr('style')}
clickPreviewApply(event){const $this=jQuery(event.currentTarget);if(!$this.hasClass('cmsmasters-palettes-preview__reset')){return}
event.stopPropagation();this.elements.$previewPalettes.removeClass('cmsmasters-color-palettes-open');this.elements.$previewDemo.removeClass('cmsmasters-palette-apply-active').addClass('cmsmasters-palette-apply-no-active');jQuery('.cmsmasters-color-palettes .wp-picker-default').trigger('click');$this.removeClass('cmsmasters-palettes-preview__reset').text('Apply');this.elements.$html.attr('data-cmsmasters-color-palette','cmsmasters-default').removeAttr('style')}
initPalettesColors(index,event){const $this=jQuery(event);const kitId=$this.data('kitId');const $html=this.elements.$html;$this.wpColorPicker({width:308,defaultColor:$this.attr('value'),change:function(e,ui){$html.css('--e-global-color-'+kitId+'',ui.color.toString())}});jQuery(document).on('click',function(e){const $element=jQuery('.cmsmasters-color-palettes .wp-picker-container');if(!$element.is(e.target)&&$element.has(e.target).length===0){this.elements.$previewPalettes.removeClass('cmsmasters-color-palettes-open')}}.bind(this));jQuery('.cmsmasters-color-palettes .wp-picker-container .wp-color-result').on('click',function(){this.elements.$previewPalettes.removeClass('cmsmasters-color-palettes-open');jQuery('.wp-picker-container.wp-picker-active').closest('.cmsmasters-color-palettes').addClass('cmsmasters-color-palettes-open')}.bind(this));jQuery('.cmsmasters-palettes-preview__demo .wp-picker-container').hover(function(){const id=jQuery(this).find('.cmsmasters-palette-color').attr('id');jQuery('label[for="'+id+'"]').addClass('cmsmasters-palette-alt-active');const text=jQuery('label[for="'+id+'"]').html();jQuery(this).find('.button.wp-color-result').html('<span class="cmsmasters-palette-alt-button">'+text+'</span>')},function(){jQuery('label[for*="cmsmasters-button-"]').removeClass('cmsmasters-palette-alt-active')})}}
new cmsmastersDemosPreview()